import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Check if input length exceeds buffer size before copying
        if (name.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        // Safe copy to buffer with proper bounds checking
        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), 10), buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
